// Format alert message for all channels
const alert = $input.first().json;
const baseUrl = process.env.N8N_WEBHOOK_BASE_URL || 'http://localhost:5678/webhook';

const EMOJI = {
  NEW_ELIGIBLE_JOB: '[NEW JOB]',
  DRAFT_READY: '[DRAFT READY]',
  NEEDS_USER_INPUT: '[ACTION REQUIRED]',
  CAPTCHA_BLOCKED: '[BLOCKED]',
  AUTH_EXPIRED: '[AUTH EXPIRED]',
  SELECTOR_BROKEN: '[SCRAPER BROKEN]',
  SUBMISSION_FAILED: '[SUBMISSION FAILED]',
  STALE_ATTENTION: '[STALE]',
  COMPANY_PENDING: '[NEW COMPANY DETECTED]'
};

const label = EMOJI[alert.alert_type] || '[ALERT]';
const approvalLink = alert.application_id
  ? `\nApprove: POST ${baseUrl}/approval {application_id: "${alert.application_id}", action: "approve"}\nReject: POST ${baseUrl}/approval {application_id: "${alert.application_id}", action: "reject"}`
  : '';

const subject = `Job Scraper ${label}: ${alert.alert_type}`;
const body = [
  `Type: ${alert.alert_type}`,
  alert.company_id ? `Company: ${alert.company_id}` : null,
  alert.job_key ? `Job Key: ${alert.job_key}` : null,
  alert.application_id ? `Application: ${alert.application_id}` : null,
  alert.source_url ? `URL: ${alert.source_url}` : null,
  `Detail: ${alert.detail}`,
  `Time: ${new Date().toISOString()}`,
  approvalLink
].filter(Boolean).join('\n');

return [{ json: { subject, body, alert } }];
